#include <iostream>
#include <random> // Required for modern C++ random numbers
#include <vector>
#include <string>
#include <iterator> // std::begin, std::end

int main() {
    // --- Setup for Random Number Generation ---
    // 1. Seed with a real random value, if available
    std::random_device rd;
    // 2. Choose a generator engine (Mersenne Twister is common)
    std::mt19937 gen(rd()); // Seed the generator

    // --- Generate Random Integer ---
    int minValInt = 1;
    int maxValInt = 100;
    // Distribution: generates integers uniformly in [minValInt, maxValInt] (inclusive)
    std::uniform_int_distribution<> distribInt(minValInt, maxValInt);
    int randomInt = distribInt(gen); // Generate the number
    std::cout << "Random Integer (" << minValInt << "-" << maxValInt << "): " << randomInt << std::endl;

    // --- Generate Random Float/Double ---
    double minValDbl = 0.0;
    double maxValDbl = 1.0;
    // Distribution: generates floating points uniformly in [minValDbl, maxValDbl) (exclusive of max)
    std::uniform_real_distribution<> distribDbl(minValDbl, maxValDbl);
    double randomDbl = distribDbl(gen); // Generate the number
    std::cout << "Random Double [" << minValDbl << "," << maxValDbl << "): " << randomDbl << std::endl;

    // --- Select Random Element from a Container ---
    std::vector<std::string> fruits = {"apple", "banana", "cherry"};
    if (!fruits.empty()) {
        // Create distribution for indices [0, size - 1]
        std::uniform_int_distribution<> distribIndex(0, fruits.size() - 1);
        int randomIndex = distribIndex(gen);
        std::cout << "Random fruit: " << fruits[randomIndex] << std::endl;

        // Alternative (less direct control over generator state per call): std::sample (C++17)
        // std::string randomFruitSample;
        // std::sample(fruits.begin(), fruits.end(), &randomFruitSample, 1, gen);
        // std::cout << "Random fruit (sample): " << randomFruitSample << std::endl;
    }

    return 0;
}

