// Note: std::string reversal using std::reverse works on bytes.
// For full Unicode correctness with multi-byte characters,
// dedicated libraries (like ICU) or careful handling of UTF-8 sequences are needed.
// This snippet shows byte reversal and a basic wide character example.

int main() {
    std::string original = "Hello C++";
    std::cout << "Original: " << original << std::endl;

    // Method 1: In-place reversal using std::reverse
    std::string reversedStr = original; // Make a copy
    std::reverse(reversedStr.begin(), reversedStr.end());
    std::cout << "Reversed (byte order): " << reversedStr << std::endl;

    // Method 2: Manual loop (byte reversal)
    std::string reversedManual = original;
    size_t n = reversedManual.length();
    for (size_t i = 0; i < n / 2; ++i) {
        std::swap(reversedManual[i], reversedManual[n - 1 - i]);
    }
     std::cout << "Reversed (manual loop): " << reversedManual << std::endl;


    // Basic wide character string reversal (platform dependent wchar_t size)
    std::wstring wideOriginal = L"你好 C++"; // Wide string literal
    std::wcout << L"Original Wide: " << wideOriginal << std::endl;
    std::wstring wideReversed = wideOriginal;
    std::reverse(wideReversed.begin(), wideReversed.end());
    std::wcout << L"Reversed Wide: " << wideReversed << std::endl;


    return 0;
}

