#include <iostream>
#include <vector>
#include <stdexcept> // For exceptions

// Calculates the Nth Fibonacci number (0-indexed) iteratively
// Returns long long to handle larger values than int
long long fibonacci(int n) {
    if (n < 0) {
        throw std::invalid_argument("Fibonacci input must be non-negative.");
    }
    if (n == 0) return 0;
    if (n == 1) return 1;

    long long a = 0;
    long long b = 1;

    for (int i = 2; i <= n; ++i) {
        // Check for potential overflow before addition (basic check)
        // Note: Requires <limits> for std::numeric_limits
        // if (b > std::numeric_limits<long long>::max() - a) {
        //     throw std::overflow_error("Fibonacci sequence overflowed long long.");
        // }
        long long next = a + b;
        a = b;
        b = next;
    }
    return b;
}

// Generates the first 'count' Fibonacci numbers
std::vector<long long> generateFibonacciSequence(int count) {
    if (count < 0) {
        throw std::invalid_argument("Count must be non-negative.");
    }
    std::vector<long long> sequence;
    sequence.reserve(count); // Reserve space if count is large
    for (int i = 0; i < count; ++i) {
        sequence.push_back(fibonacci(i));
    }
    return sequence;
}

int main() {
    try {
        int n = 10;
        std::cout << "Fibonacci number F(" << n << "): " << fibonacci(n) << std::endl;

        int numTerms = 15;
        std::cout << "First " << numTerms << " Fibonacci numbers:" << std::endl;
        std::vector<long long> sequence = generateFibonacciSequence(numTerms);
        std::cout << "[";
        for (size_t i = 0; i < sequence.size(); ++i) {
            std::cout << sequence[i] << (i == sequence.size() - 1 ? "" : ", ");
        }
        std::cout << "]" << std::endl;

        // Example potentially large number (F(93) overflows signed 64-bit)
        int largeN = 90;
        std::cout << "Fibonacci number F(" << largeN << "): " << fibonacci(largeN) << std::endl;

        // Example: F(94) will likely wrap around or be incorrect if not using BigInt lib
        // int tooLargeN = 94;
        // std::cout << "Fibonacci number F(" << tooLargeN << "): " << fibonacci(tooLargeN) << std::endl;

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }
    return 0;
}

