#include <iostream>
#include <stdexcept> // For exceptions
#include <limits>    // For numeric limits (optional overflow check)

// Calculates factorial N! iteratively
// Returns unsigned long long for maximum range within standard types
// Note: Factorial of 21+ overflows even unsigned 64-bit integers.
unsigned long long factorial(int n) {
    if (n < 0) {
        throw std::invalid_argument("Factorial is not defined for negative numbers.");
    }

    unsigned long long result = 1;
    if (n == 0) {
        return result;
    }

    for (int i = 2; i <= n; ++i) {
        // Basic overflow check (optional)
        // if (result > std::numeric_limits<unsigned long long>::max() / i) {
        //     throw std::overflow_error("Factorial overflowed unsigned long long.");
        // }
        result *= i;
    }
    return result;
}

int main() {
    try {
        int num = 5;
        std::cout << "Factorial of " << num << " is: " << factorial(num) << std::endl;

        num = 0;
        std::cout << "Factorial of " << num << " is: " << factorial(num) << std::endl;

        num = 20; // Max for signed long long, fits in unsigned long long
        std::cout << "Factorial of " << num << " is: " << factorial(num) << std::endl;

        // Example: 21! overflows unsigned long long, result will wrap around
        // num = 21;
