#include <iostream>
#include <cmath> // For sqrt

// Checks if a number is prime
bool isPrime(long long n) { // Use long long for a wider range
    if (n <= 1) return false;
    if (n <= 3) return true;
    if (n % 2 == 0 || n % 3 == 0) return false;

    // Check factors from 5 upwards, stepping by 6
    long long limit = static_cast<long long>(sqrt(n));
    for (long long i = 5; i <= limit; i += 6) {
        if (n % i == 0 || n % (i + 2) == 0) {
            return false; // Divisor found
        }
    }
    return true; // No divisors found
}

int main() {
    long long numbersToCheck[] = { 2LL, 3LL, 4LL, 17LL, 25LL, 29LL, 97LL, 100LL, 1LL, -5LL, 1000000007LL };
    // Note: LL suffix denotes long long literal

    for (long long n : numbersToCheck) {
        if (isPrime(n)) {
            std::cout << n << " is prime." << std::endl;
        } else {
            std::cout << n << " is not prime." << std::endl;
        }
    }
    return 0;
}

