#include <iostream>
#include <fstream>   // For file streams (ifstream)
#include <string>
#include <sstream>   // For reading file into string buffer
#include <vector>    // For reading lines into vector

// Note: Requires C++11 or later for range-based for loops and other conveniences.

int main() {
    std::string filename = "cpp_read_test.txt";

    // Create a dummy file for reading
    { // Use scope to ensure ofstream is closed after writing
        std::ofstream outFile(filename);
        if (!outFile) {
            std::cerr << "Error creating dummy file: " << filename << std::endl;
            return 1;
        }
        outFile << "Line 1 from C++. " << std::endl;
        outFile << "Second line here." << std::endl;
        outFile << "End of file marker." << std::endl;
        // outFile closes automatically when it goes out of scope
        std::cout << "Created dummy file '" << filename << "' for reading." << std::endl;
    }

    std::cout << "\n--- Reading file '" << filename << "' ---" << std::endl;
    std::ifstream inFile(filename); // Open file for reading

    if (!inFile.is_open()) {
        std::cerr << "Error: Could not open file '" << filename << "' for reading." << std::endl;
    } else {
        // Method 1: Read entire file into a string using stringstream
        std::cout << "\n--- Reading using stringstream ---" << std::endl;
        std::stringstream buffer;
        buffer << inFile.rdbuf(); // Read entire stream buffer
        std::string fileContent = buffer.str();
        std::cout << "File content as single string:" << std::endl;
        std::cout << fileContent; // Print content
        std::cout << "--- End of stringstream read ---" << std::endl;

        // Reset stream state to read again for method 2
        inFile.clear();             // Clear any error flags (like EOF)
        inFile.seekg(0, std::ios::beg); // Go back to the beginning of the file

        // Method 2: Read line by line into a vector
        std::cout << "\n--- Reading line by line ---" << std::endl;
        std::vector<std::string> lines;
        std::string currentLine;
        int lineNum = 1;
        while (std::getline(inFile, currentLine)) { // Read until EOF
            lines.push_back(currentLine);
            std::cout << "Line " << lineNum++ << ": " << currentLine << std::endl;
        }
        std::cout << "--- End of line-by-line read ---" << std::endl;

        inFile.close(); // Close the file stream explicitly (good practice)
    }

    // Clean up dummy file using C standard library function (or C++17 filesystem)
    if (std::remove(filename.c_str()) != 0) {
         std::cerr << "Error deleting dummy file." << std::endl;
    } else {
         std::cout << "\nCleaned up dummy file '" << filename << "'." << std::endl;
    }

    return 0;
}

