#include <iostream>
#include <fstream> // For ofstream
#include <string>
#include <vector>

int main() {
    std::string filename = "output_cpp.txt";
    std::vector<std::string> initialLines = {
        "First line written by C++ ofstream.",
        "Second line."
    };
    std::string lineToAppend = "Third line, appended.";

    // --- Write using ofstream (truncates/overwrites by default) ---
    std::cout << "--- Writing to '" << filename << "' (overwrite) ---" << std::endl;
    { // Scope for RAII - ensures file is closed even if errors occur below
        std::ofstream outFile(filename); // Open in truncate mode (default)
        if (!outFile) {
            std::cerr << "Error opening file '" << filename << "' for writing." << std::endl;
        } else {
            for (const auto& line : initialLines) {
                outFile << line << std::endl; // Write each line + newline
            }
            std::cout << "Successfully wrote " << initialLines.size() << " lines." << std::endl;
            // outFile closes automatically at end of scope
        }
    } // outFile is closed here

    // --- Append using ofstream with append mode ---
    std::cout << "\n--- Appending to '" << filename << "' ---" << std::endl;
    {
        // Open in append mode (std::ios::app)
        std::ofstream appendFile(filename, std::ios::app);
        if (!appendFile) {
             std::cerr << "Error opening file '" << filename << "' for appending." << std::endl;
        } else {
            appendFile << lineToAppend << std::endl;
            std::cout << "Successfully appended content." << std::endl;
            // appendFile closes automatically
        }
    } // appendFile is closed here

    // --- Display final content (by reading back) ---
    std::cout << "\n--- Final content of '" << filename << "': ---" << std::endl;
    std::ifstream readFile(filename);
    if (!readFile) {
        std::cerr << "File '" << filename << "' not found or could not be opened for display." << std::endl;
    } else {
        std::string line;
        while (std::getline(readFile, line)) {
            std::cout << line << std::endl;
        }
        // readFile closes automatically (RAII)
    }

    // Optional: Clean up
    // std::remove(filename.c_str());

    return 0;
}

