namespace fs = std::filesystem; // Alias for convenience

int main() {
    std::string fileToCheck = "cpp_exists_test.cpp";
    std::string dirToCheck = "my_cpp_dir";
    std::string nonExistent = "no_such_cpp_thing.ext";

    // Create dummy file/dir
    try {
        // Create empty file
        { std::ofstream dummyFile(fileToCheck); }
        // Create directory
        fs::create_directory(dirToCheck);
        std::cout << "Created dummy file '" << fileToCheck << "' and directory '" << dirToCheck << "'" << std::endl;
    } catch (const fs::filesystem_error& e) {
        std::cerr << "Error creating dummies: " << e.what() << std::endl;
        return 1;
    } catch (...) { // Catch any other exceptions during creation
         std::cerr << "Unknown error creating dummies." << std::endl;
         return 1;
    }


    std::cout << "\n--- Checking Existence and Type using <filesystem> ---" << std::endl;

    // fs::exists(path) - Checks if path exists (file, dir, link etc.)
    std::cout << "'" << fileToCheck << "' exists? " << fs::exists(fileToCheck) << std::endl;
    std::cout << "'" << dirToCheck << "' exists? " << fs::exists(dirToCheck) << std::endl;
    std::cout << "'" << nonExistent << "' exists? " << fs::exists(nonExistent) << std::endl;

    // fs::is_regular_file(path) - Checks if it exists AND is a regular file
    std::cout << "\n'" << fileToCheck << "' is regular file? " << fs::is_regular_file(fileToCheck) << std::endl;
    std::cout << "'" << dirToCheck << "' is regular file? " << fs::is_regular_file(dirToCheck) << std::endl; // False

    // fs::is_directory(path) - Checks if it exists AND is a directory
    std::cout << "\n'" << fileToCheck << "' is directory? " << fs::is_directory(fileToCheck) << std::endl; // False
    std::cout << "'" << dirToCheck << "' is directory? " << fs::is_directory(dirToCheck) << std::endl;


    // Clean up
    try {
         fs::remove(fileToCheck); // Removes file or empty directory
         fs::remove(dirToCheck);  // Removes file or empty directory
         std::cout << "\nCleaned up dummy file and directory." << std::endl;
    } catch (const fs::filesystem_error& e) {
        std::cerr << "\nError during cleanup: " << e.what() << std::endl;
    }

    // Note: If <filesystem> is not available (pre-C++17), you might try
