#include <iostream>
#include <chrono>   // For system_clock, time_point
#include <ctime>    // For time_t, tm, localtime_s/gmtime_s (safer C functions), strftime
#include <iomanip>  // For put_time (C++11 way to format time)
#include <sstream>  // To use put_time easily

// Note: C++20 introduces much richer date/time formatting and handling.
// This example uses C++11/17 compatible features (<chrono> + <ctime>).

int main() {
    std::cout << "--- Current Date and Time ---" << std::endl;

    // Get current time point from system clock
    auto now = std::chrono::system_clock::now();
    std::cout << "System Clock Now: (Implementation defined output)" << std::endl; // Output depends on how time_point streams

    // Convert time_point to time_t (C-style seconds since epoch)
    std::time_t now_c = std::chrono::system_clock::to_time_t(now);

    // Convert time_t to broken-down time struct (tm)
    // Use safer versions if available (localtime_s, gmtime_s)
    std::tm local_tm;
    #ifdef _WIN32
        localtime_s(&local_tm, &now_c); // Windows safe version
    #else
        localtime_r(&now_c, &local_tm); // POSIX safe version
    #endif
    // std::tm* local_tm_ptr = std::localtime(&now_c); // Less safe version

    std::cout << "\n--- Formatted Time (using std::put_time, C++11) ---" << std::endl;
    // std::put_time requires <iomanip> and uses strftime format codes
    std::cout << "Default Locale: " << std::put_time(&local_tm, "%c") << std::endl;
    std::cout << "YYYY-MM-DD: " << std::put_time(&local_tm, "%Y-%m-%d") << std::endl;
    std::cout << "HH:MM:SS (24hr): " << std::put_time(&local_tm, "%H:%M:%S") << std::endl;
    std::cout << "Readable: " << std::put_time(&local_tm, "%A, %B %d, %Y at %I:%M:%S %p") << std::endl;

    // --- Alternative Formatting using strftime (C-style) ---
    char buffer[80];
    std::strftime(buffer, sizeof(buffer), "%Y-%m-%d %H:%M:%S", &local_tm);
    std::cout << "\nstrftime YYYY-MM-DD HH:MM:SS: " << buffer << std::endl;

    std::cout << "\n--- Components (from tm struct, 0-based month!) ---" << std::endl;
    std::cout << "Year: " << local_tm.tm_year + 1900 << std::endl; // Years since 1900
    std::cout << "Month: " << local_tm.tm_mon + 1 << std::endl; // Month [0-11]
    std::cout << "Day: " << local_tm.tm_mday << std::endl;
    std::cout << "Hour: " << local_tm.tm_hour << std::endl;
    std::cout << "Minute: " << local_tm.tm_min << std::endl;
    std::cout << "Second: " << local_tm.tm_sec << std::endl;
    std::cout << "DayOfWeek: " << local_tm.tm_wday << " (0=Sun, 1=Mon,...)" << std::endl;
    std::cout << "DayOfYear: " << local_tm.tm_yday << " [0-365]" << std::endl;
    // Timezone info from tm is platform-dependent and sometimes unreliable.

    std::cout << "\n--- Unix Epoch Seconds ---" << std::endl;
    auto seconds_since_epoch = std::chrono::duration_cast<std::chrono::seconds>(now.time_since_epoch()).count();
    std::cout << "Seconds since epoch (system_clock): " << seconds_since_epoch << std::endl;
    // Note: system_clock epoch is usually Unix epoch, but not guaranteed by standard.

    return 0;
}

