        // std::cout << "Maximum value: " << *maxItEmpty << std::endl;
    }


     // Example with C-style array
     double c_array[] = {1.5, -0.5, 3.14, 2.71};
     size_t array_size = sizeof(c_array) / sizeof(c_array[0]);
